import{_ as s,o as t,c as a,ai as i}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"Token Use and Costs","description":"","frontmatter":{"summary":"How OpenSoul builds prompt context and reports token usage + costs","read_when":["Explaining token usage, costs, or context windows","Debugging context growth or compaction behavior"],"title":"Token Use and Costs"},"headers":[],"relativePath":"reference/token-use.md","filePath":"reference/token-use.md","lastUpdated":null}'),n={name:"reference/token-use.md"};function o(r,e,l,c,p,h){return t(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="token-use-costs" tabindex="-1"><a class="header-anchor" href="#token-use-costs">#</a> Token use &amp; costs</h1><p>OpenSoul tracks <strong>tokens</strong>, not characters. Tokens are model-specific, but most OpenAI-style models average ~4 characters per token for English text.</p><h2 id="how-the-system-prompt-is-built" tabindex="-1"><a class="header-anchor" href="#how-the-system-prompt-is-built">#</a> How the system prompt is built</h2><p>OpenSoul assembles its own system prompt on every run. It includes:</p><ul><li>Tool list + short descriptions</li><li>Skills list (only metadata; instructions are loaded on demand with <code>read</code>)</li><li>Self-update instructions</li><li>Workspace + bootstrap files (<code>AGENTS.md</code>, <code>SOUL.md</code>, <code>TOOLS.md</code>, <code>IDENTITY.md</code>, <code>USER.md</code>, <code>HEARTBEAT.md</code>, <code>BOOTSTRAP.md</code> when new). Large files are truncated by <code>agents.defaults.bootstrapMaxChars</code> (default: 20000).</li><li>Time (UTC + user timezone)</li><li>Reply tags + heartbeat behavior</li><li>Runtime metadata (host/OS/model/thinking)</li></ul><p>See the full breakdown in <a href="/docs/concepts/system-prompt">System Prompt</a>.</p><h2 id="what-counts-in-the-context-window" tabindex="-1"><a class="header-anchor" href="#what-counts-in-the-context-window">#</a> What counts in the context window</h2><p>Everything the model receives counts toward the context limit:</p><ul><li>System prompt (all sections listed above)</li><li>Conversation history (user + assistant messages)</li><li>Tool calls and tool results</li><li>Attachments/transcripts (images, audio, files)</li><li>Compaction summaries and pruning artifacts</li><li>Provider wrappers or safety headers (not visible, but still counted)</li></ul><p>For a practical breakdown (per injected file, tools, skills, and system prompt size), use <code>/context list</code> or <code>/context detail</code>. See <a href="/docs/concepts/context">Context</a>.</p><h2 id="how-to-see-current-token-usage" tabindex="-1"><a class="header-anchor" href="#how-to-see-current-token-usage">#</a> How to see current token usage</h2><p>Use these in chat:</p><ul><li><code>/status</code> → <strong>emoji‑rich status card</strong> with the session model, context usage, last response input/output tokens, and <strong>estimated cost</strong> (API key only).</li><li><code>/usage off|tokens|full</code> → appends a <strong>per-response usage footer</strong> to every reply. <ul><li>Persists per session (stored as <code>responseUsage</code>).</li><li>OAuth auth <strong>hides cost</strong> (tokens only).</li></ul></li><li><code>/usage cost</code> → shows a local cost summary from OpenSoul session logs.</li></ul><p>Other surfaces:</p><ul><li><strong>TUI/Web TUI:</strong> <code>/status</code> + <code>/usage</code> are supported.</li><li><strong>CLI:</strong> <code>opensoul status --usage</code> and <code>opensoul channels list</code> show provider quota windows (not per-response costs).</li></ul><h2 id="cost-estimation-when-shown" tabindex="-1"><a class="header-anchor" href="#cost-estimation-when-shown">#</a> Cost estimation (when shown)</h2><p>Costs are estimated from your model pricing config:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>models.providers.&lt;provider&gt;.models[].cost</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>These are <strong>USD per 1M tokens</strong> for <code>input</code>, <code>output</code>, <code>cacheRead</code>, and <code>cacheWrite</code>. If pricing is missing, OpenSoul shows tokens only. OAuth tokens never show dollar cost.</p><h2 id="cache-ttl-and-pruning-impact" tabindex="-1"><a class="header-anchor" href="#cache-ttl-and-pruning-impact">#</a> Cache TTL and pruning impact</h2><p>Provider prompt caching only applies within the cache TTL window. OpenSoul can optionally run <strong>cache-ttl pruning</strong>: it prunes the session once the cache TTL has expired, then resets the cache window so subsequent requests can re-use the freshly cached context instead of re-caching the full history. This keeps cache write costs lower when a session goes idle past the TTL.</p><p>Configure it in <a href="/docs/gateway/configuration">Gateway configuration</a> and see the behavior details in <a href="/docs/concepts/session-pruning">Session pruning</a>.</p><p>Heartbeat can keep the cache <strong>warm</strong> across idle gaps. If your model cache TTL is <code>1h</code>, setting the heartbeat interval just under that (e.g., <code>55m</code>) can avoid re-caching the full prompt, reducing cache write costs.</p><p>For Anthropic API pricing, cache reads are significantly cheaper than input tokens, while cache writes are billed at a higher multiplier. See Anthropic’s prompt caching pricing for the latest rates and TTL multipliers: <a href="https://docs.anthropic.com/docs/build-with-claude/prompt-caching" target="_blank" rel="noreferrer">https://docs.anthropic.com/docs/build-with-claude/prompt-caching</a></p><h3 id="example-keep-1h-cache-warm-with-heartbeat" tabindex="-1"><a class="header-anchor" href="#example-keep-1h-cache-warm-with-heartbeat">#</a> Example: keep 1h cache warm with heartbeat</h3><div class="language-yaml vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">agents</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  defaults</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    model</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">      primary</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;anthropic/claude-opus-4-6&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    models</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      &quot;anthropic/claude-opus-4-6&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">        params</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">          cacheRetention</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;long&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    heartbeat</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">      every</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;55m&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><h2 id="tips-for-reducing-token-pressure" tabindex="-1"><a class="header-anchor" href="#tips-for-reducing-token-pressure">#</a> Tips for reducing token pressure</h2><ul><li>Use <code>/compact</code> to summarize long sessions.</li><li>Trim large tool outputs in your workflows.</li><li>Keep skill descriptions short (skill list is injected into the prompt).</li><li>Prefer smaller models for verbose, exploratory work.</li></ul><p>See <a href="/docs/tools/skills">Skills</a> for the exact skill list overhead formula.</p>`,29)])])}const m=s(n,[["render",o]]);export{u as __pageData,m as default};
